const raw = ($json.content || []).find(b => b.type === 'text')?.text || '';

const clean = raw.trim().startsWith('```')
  ? raw.trim().replace(/^```[a-z]*\n?/, '').replace(/\n?```$/, '').trim()
  : raw.trim();

if (!clean.startsWith('<') && !clean.toLowerCase().includes('<html')) {
  throw new Error('Claude did not return HTML. Got: ' + clean.slice(0, 200));
}

const productId = $('Build Claude Request Body').first().json.productId;

return [{ json: { html: clean, productId } }];

const productId = $json.productId || $('Webhook Trigger').first().json.body.product_id;
const specItems = $('Fetch Product Spec').all();
const specRaw = specItems.length > 0 ? specItems[0].json : [];
const product = Array.isArray(specRaw) ? (specRaw[0] || {}) : specRaw;

const supabaseUrl = $vars.SUPABASE_URL;
const htmlUrl = supabaseUrl + '/storage/v1/object/public/templates/ebooks/' + productId + '/ebook.html';
const pdfUrl  = supabaseUrl + '/storage/v1/object/public/templates/ebooks/' + productId + '/ebook.pdf';

const title = product.name || product.title || 'Ebook';
const description = product.description || '';
const price = product.suggested_price_usd ? '$' + Number(product.suggested_price_usd).toFixed(2) : '';

const dateStr = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

const html = '<!DOCTYPE html><html><body style="font-family:sans-serif;background:#0A0A0A;color:#fff;margin:0;padding:0">'
  + '<div style="max-width:640px;margin:0 auto;padding:32px 24px">'
  + '<p style="color:#C8F53A;font-size:12px;letter-spacing:2px;margin:0 0 8px">CIPHER STUDIO</p>'
  + '<h1 style="font-size:32px;color:#fff;margin:0 0 4px">Ebook Design Complete</h1>'
  + '<p style="color:#666;margin:0 0 32px;font-size:14px">' + dateStr + '</p>'
  + '<div style="background:#111;border:1px solid #222;border-radius:8px;padding:24px;margin-bottom:24px">'
  + '<p style="color:#C8F53A;font-size:11px;letter-spacing:1px;margin:0 0 8px">EBOOK GUIDE</p>'
  + '<h2 style="margin:0 0 12px;font-size:22px">' + title + '</h2>'
  + (description ? '<p style="color:#aaa;margin:0 0 16px;line-height:1.6">' + description + '</p>' : '')
  + (price ? '<p style="margin:0"><strong style="color:#C8F53A">Price:</strong> ' + price + '</p>' : '')
  + '</div>'
  + '<div style="background:#111;border:1px solid #C8F53A;border-radius:8px;padding:20px;margin-bottom:16px;text-align:center">'
  + '<p style="color:#C8F53A;font-size:11px;letter-spacing:1px;margin:0 0 12px">DOWNLOAD</p>'
  + '<a href="' + pdfUrl + '" style="background:#C8F53A;color:#0A0A0A;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;font-size:14px;margin-right:12px">Download PDF</a>'
  + '<a href="' + htmlUrl + '" style="background:transparent;color:#C8F53A;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;font-size:14px;border:1px solid #C8F53A">Preview HTML</a>'
  + '</div>'
  + '<p style="color:#aaa;font-size:14px;text-align:center;margin:16px 0">Review and approve, or reply with revision notes.</p>'
  + '<p style="color:#444;font-size:12px;text-align:center">Supabase products table &nbsp;&middot;&nbsp; cipherstudio.co</p>'
  + '</div></body></html>';

return [{ json: {
  subject: 'Ebook Ready: ' + title,
  html,
  pdfUrl,
  htmlUrl,
  productId
} }];
